const items = $input.all();

let alecsharpieData = [];
let genevieveRaw = '';

for (const item of items) {
  const data = item.json.data;

  if (typeof data === 'string' && data.includes('Common name')) {
    genevieveRaw = data;
  } else if (typeof data === 'string' && data.includes('common_name')) {
    alecsharpieData = JSON.parse(data);
  }
}

// Normaliser alecsharpie
const fromAlecsharpie = alecsharpieData.map(p => ({
  json: {
    name_en: p.common_name.toLowerCase().trim(),
    name_latin: p.scientific_name || null,
    type: p.type || null,
    source: 'alecsharpie',
    helps: p.helps || [],
    helped_by: p.helped_by || [],
    avoid: p.avoid || []
  }
}));

function parseCSVLine(line) {
  const result = [];
  let current = '';
  let inQuotes = false;
  for (let i = 0; i < line.length; i++) {
    const char = line[i];
    if (char === '"') {
      inQuotes = !inQuotes;
    } else if (char === ',' && !inQuotes) {
      result.push(current.trim());
      current = '';
    } else {
      current += char;
    }
  }
  result.push(current.trim());
  return result;
}

const lines = genevieveRaw.trim().split('\n');
const headers = parseCSVLine(lines[0]);
const fromGenevieve = lines.slice(1).map(line => {
  const vals = parseCSVLine(line);
  const p = {};
  headers.forEach((h, i) => p[h.trim()] = (vals[i] || '').trim());
  return {
    json: {
      name_en: (p['Common name'] || '').toLowerCase().trim(),
      name_latin: (p['Scientific name'] || '').trim() || null,
      type: 'Vegetable',
      source: 'genevieve',
      helps: p['Helps'] ? p['Helps'].split(/[;,]/).map(s => s.trim().toLowerCase()).filter(Boolean) : [],
      helped_by: p['Helped by'] ? p['Helped by'].split(/[;,]/).map(s => s.trim().toLowerCase()).filter(Boolean) : [],
      avoid: p['Avoid'] ? p['Avoid'].split(/[;,]/).map(s => s.trim().toLowerCase()).filter(Boolean) : []
    }
  };
}).filter(item => item.json.name_en);

// Merge og dedupliker på name_en
const merged = {};
[...fromAlecsharpie, ...fromGenevieve].forEach(item => {
  const key = item.json.name_en;
  if (key && !merged[key]) {
    merged[key] = item;
  }
});

return Object.values(merged);

const nameLatin = ($input.item.json.name_latin || '').replace(/"/g, '').trim();

return {
  json: {
    ...$input.item.json,
    sparql_query: `SELECT ?item ?familyLabel ?nameDa WHERE {
  ?item wdt:P225 "${nameLatin}".
  OPTIONAL { ?item wdt:P171 ?family. }
  OPTIONAL {
    ?item p:P225 ?statement.
    ?statement pq:P1705 ?nameDa.
    FILTER(LANG(?nameDa) = "da")
  }
  SERVICE wikibase:label { bd:serviceParam wikibase:language "da,en". }
} LIMIT 1`
  }
};

const wikidataResponse = $input.item.json;
const originalItem = $('Byg SPARQL query').item.json;
const dataStr = wikidataResponse.data || '';

let familyLabel = null;

try {
  const parsed = JSON.parse(dataStr);
  const bindings = parsed?.results?.bindings || [];
  if (bindings.length > 0) {
    familyLabel = bindings[0]?.familyLabel?.value || null;
  }
} catch(e) {}

return {
  json: {
    ...originalItem,
    family: familyLabel,
    sparql_query: undefined
  }
};

