const ollamaResponse = $input.item.json;
const originalItem = $('Byg SPARQL query').item.json;
const wikidataItem = $('Parse Wikidata respons').item.json;
const nameDaItem = $('Parse Ollama name_da').item.json;
const soilItem = $('Parse Ollama soil').item.json;
const raw = (ollamaResponse.response || '').trim();

let depletes = [];
let restores = [];

const depletesMatch = raw.match(/DEPLETES:\s*(.+)/i);
const restoresMatch = raw.match(/RESTORES:\s*(.+)/i);

if (depletesMatch) {
  depletes = depletesMatch[1].split(',')
    .map(s => s.trim().toLowerCase())
    .filter(s => s !== 'none' && s !== '');
}

if (restoresMatch) {
  restores = restoresMatch[1].split(',')
    .map(s => s.trim().toLowerCase())
    .filter(s => s !== 'none' && s !== '');
}

return {
  json: {
    ...originalItem,
    family: wikidataItem.family,
    name_da: nameDaItem.name_da,
    prefers_soil: soilItem.prefers_soil,
    depletes: depletes,
    restores: restores,
    sparql_query: undefined
  }
};

const ollamaResponse = $input.item.json;
const originalItem = $('Byg SPARQL query').item.json;
const wikidataItem = $('Parse Wikidata respons').item.json;
const nameDaItem = $('Parse Ollama name_da').item.json;
const soilItem = $('Parse Ollama soil').item.json;
const nutrientsItem = $('Parse Ollama nutrients').item.json;
const raw = (ollamaResponse.response || '').trim();

let follows_well_after = [];
let avoid_after = [];

const followsMatch = raw.match(/FOLLOWS_WELL_AFTER:\s*(.+)/i);
const avoidMatch = raw.match(/AVOID_AFTER:\s*(.+)/i);

if (followsMatch) {
  follows_well_after = followsMatch[1].split(',')
    .map(s => s.replace(/\(.*?\)/g, '').trim().toLowerCase())
    .filter(s => s !== 'none' && s !== '' && s.length < 20);
}

if (avoidMatch) {
  avoid_after = avoidMatch[1].split(',')
    .map(s => s.replace(/\(.*?\)/g, '').trim().toLowerCase())
    .filter(s => s !== 'none' && s !== '' && s.length < 20);
}

return {
  json: {
    ...originalItem,
    sparql_query: undefined,
    family: wikidataItem.family,
    name_da: nameDaItem.name_da,
    prefers_soil: soilItem.prefers_soil,
    depletes: (nutrientsItem.depletes || []).filter(s => s.length < 20),
    restores: (nutrientsItem.restores || []).filter(s => s.length < 20),
    follows_well_after: follows_well_after,
    avoid_after: avoid_after
  }
};

