const ollamaResponse = $input.item.json;
const cropRotationItem = $('Parse Ollama crop rotation').item.json;
const raw = (ollamaResponse.response || '').trim();

const grows_in = raw
  .split(',')
  .map(s => s.trim().toLowerCase())
  .filter(Boolean);

return {
  json: {
    ...cropRotationItem,
    grows_in: grows_in
  }
};

const items = $input.first().json.data;
const allPlants = Array.isArray(items) ? items : [items];

const output = {
  plants: allPlants,
  count: allPlants.length,
  generated_at: new Date().toISOString()
};

return {
  json: {},
  binary: {
    data: await this.helpers.prepareBinaryData(
      Buffer.from(JSON.stringify(output, null, 2)),
      'staging_plants.json',
      'application/json'
    )
  }
};

const item = $input.item.json;
return {
  json: {
    ...item,
    name_en: (item.name_en || '').replace(/['"\\]/g, '').replace(/\s*\/\s*.*/g, '').trim(),
    name_latin: (item.name_latin || '').replace(/['"\\]/g, '').trim()
  }
};
